import os
import uuid
import smtplib
from email.mime.text import MIMEText
from datetime import datetime, timedelta

from flask import Flask, request, jsonify

app = Flask(__name__)

# --- Configuration ---
# In a real app, these would come from environment variables or a config file
app.config['SECRET_KEY'] = os.getenv('FLASK_SECRET_KEY', 'your_secret_key_for_jwt_or_session')
app.config['MAIL_SERVER'] = os.getenv('MAIL_SERVER', 'smtp.mailtrap.io')
app.config['MAIL_PORT'] = int(os.getenv('MAIL_PORT', 2525))
app.config['MAIL_USERNAME'] = os.getenv('MAIL_USERNAME', 'your_mailtrap_username')
app.config['MAIL_PASSWORD'] = os.getenv('MAIL_PASSWORD', 'your_mailtrap_password')
app.config['MAIL_USE_TLS'] = os.getenv('MAIL_USE_TLS', 'True').lower() == 'true'
app.config['MAIL_USE_SSL'] = os.getenv('MAIL_USE_SSL', 'False').lower() == 'true'
app.config['RESET_LINK_BASE_URL'] = os.getenv('RESET_LINK_BASE_URL', 'http://localhost:3000/reset-password')
app.config['TOKEN_EXPIRATION_HOURS'] = int(os.getenv('TOKEN_EXPIRATION_HOURS', 1))
app.config['SENDER_EMAIL'] = os.getenv('SENDER_EMAIL', 'no-reply@yourdomain.com')


# --- Dummy Database (for MVP) ---
# In a real application, this would be a proper database (SQLAlchemy, Peewee, etc.)
# We're simulating users and password reset tokens.
users_db = {
    "user1@example.com": {"id": 1, "username": "user1"},
    "user2@example.com": {"id": 2, "username": "user2"}
}

# Stores { token: { "email": "user@example.com", "expires_at": datetime_object } }
reset_tokens_db = {}


# --- Email Sending Function ---
def send_email(to_email, subject, body):
    msg = MIMEText(body)
    msg['Subject'] = subject
    msg['From'] = app.config['SENDER_EMAIL']
    msg['To'] = to_email

    try:
        with smtplib.SMTP(app.config['MAIL_SERVER'], app.config['MAIL_PORT']) as server:
            if app.config['MAIL_USE_TLS']:
                server.starttls()
            elif app.config['MAIL_USE_SSL']: # Less common for SMTP, typically handled by SMTPS
                server = smtplib.SMTP_SSL(app.config['MAIL_SERVER'], app.config['MAIL_PORT'])

            server.login(app.config['MAIL_USERNAME'], app.config['MAIL_PASSWORD'])
            server.send_message(msg)
        return True
    except Exception as e:
        app.logger.error(f"Failed to send email to {to_email}: {e}")
        return False


# --- API Endpoint ---
@app.route('/request-password-reset', methods=['POST'])
def request_password_reset():
    data = request.get_json()
    email = data.get('email')

    if not email:
        return jsonify({"message": "Email is required"}), 400

    # 1. Check if user exists (in a real app, query your user database)
    if email not in users_db:
        # For security, we often return a generic success message even if the user doesn't exist
        # to prevent enumeration of registered emails.
        return jsonify({"message": "If an account with that email exists, a password reset link has been sent."}), 200

    # 2. Generate a random, unique token
    token = str(uuid.uuid4())

    # 3. Store the token with the user's email and an expiration timestamp
    expires_at = datetime.utcnow() + timedelta(hours=app.config['TOKEN_EXPIRATION_HOURS'])
    reset_tokens_db[token] = {
        "email": email,
        "expires_at": expires_at
    }
    app.logger.info(f"Generated token for {email}: {token}. Expires at {expires_at}")

    # 4. Create the reset link
    reset_link = f"{app.config['RESET_LINK_BASE_URL']}?token={token}"

    # 5. Send the reset email
    subject = "Password Reset Request"
    body = f"""
    Hello,

    You have requested a password reset for your account.
    Please click on the following link to reset your password:

    {reset_link}

    This link will expire in {app.config['TOKEN_EXPIRATION_HOURS']} hour(s).

    If you did not request this, please ignore this email.

    Thanks,
    Your App Team
    """

    if send_email(email, subject, body):
        return jsonify({"message": "If an account with that email exists, a password reset link has been sent."}), 200
    else:
        # In a real app, you might want to log this error more specifically
        return jsonify({"message": "Failed to send reset email. Please try again later."}), 500


# --- Example Endpoint to Simulate Token Validation/Reset (for completeness, not strictly requested) ---
@app.route('/reset-password-confirm', methods=['POST'])
def reset_password_confirm():
    data = request.get_json()
    token = data.get('token')
    new_password = data.get('new_password')

    if not token or not new_password:
        return jsonify({"message": "Token and new_password are required"}), 400

    token_info = reset_tokens_db.get(token)

    if not token_info:
        return jsonify({"message": "Invalid or expired token"}), 400

    if datetime.utcnow() > token_info['expires_at']:
        # Optionally remove expired token
        del reset_tokens_db[token]
        return jsonify({"message": "Invalid or expired token"}), 400

    user_email = token_info['email']

    # In a real app:
    # 1. Hash the new_password (e.g., using bcrypt)
    # 2. Update the user's password in the `users_db` for `user_email`
    # 3. Invalidate/delete the token from `reset_tokens_db` after successful reset

    # Simulating password update and token deletion
    app.logger.info(f"User {user_email} successfully reset password with token {token}")
    del reset_tokens_db[token] # Invalidate the token after use

    return jsonify({"message": "Password has been successfully reset."}), 200


if __name__ == '__main__':
    # For local development, you might want to print tokens and emails to console
    # instead of sending actual emails. Mailtrap.io is a good service for testing emails.
    app.run(debug=True, port=5000)